"""
MKT Context — Luke chapters 12–13 (94 verses)
Output: data/commentary/mkt-context/luke.json
Run: python3 scripts/zc-context-luke-12-13.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH12_13 = {
"12": {
"1": "<p>The 'myriads of crowd' (myriadas tou ochlou) pressing around Jesus sets the scene for a private instruction to the disciples that the crowd overhears — a common Lukan pedagogical device. The 'leaven of the Pharisees' (zymē tōn Pharisaiōn) uses a common Jewish metaphorical field: leaven in Jewish thought was associated with corruption and moral permeation, especially in the Passover context (Exod 12:15-20; 1 Cor 5:6-8). The Dead Sea Scrolls similarly used moral-permeation language for the corruption spreading through the community from 'men of the pit' (CD II.5-13).</p>",
"2": "<p>The disclosure-of-hidden-things saying echoes Jewish wisdom tradition about divine omniscience revealing all at judgment (Pss 44:21; 90:8; Sir 1:30; 17:15-20; 1 Enoch 63:3). In the Greco-Roman world, the concept of philosophical truth eventually becoming public — the hidden becoming revealed — was also a commonplace. Jesus applies it specifically to hypocrisy (v.1), where the public performance contradicts the hidden reality. The saying establishes that pretense is ultimately futile before divine disclosure.</p>",
"3": "<p>The saying that 'what you say in darkness will be heard in the light, and what you whisper in the ear will be proclaimed from rooftops' inverts typical expectations about private communication. Rooftop proclamation was the ancient equivalent of public announcement — roofs in Palestinian houses were used as elevated public platforms for announcements (cf. Acts 10:9; 2 Sam 16:22). The saying warns that private speech before God is functionally equivalent to public speech — secrecy is illusory.</p>",
"4": "<p>'My friends' (philoi mou) — Luke's unique address here reflects a warm relational category; Jesus names his disciples as friends rather than merely servants or followers. The exhortation 'do not fear those who kill the body' draws on Jewish martyrdom theology that distinguished between bodily death and ultimate divine judgment. Second Maccabees and 4 Maccabees extensively develop the theology that tyrants can kill the body but not the soul — that the martyrs' death was absorbed into divine vindication (2 Macc 7:9-11; 4 Macc 13:14-17).</p>",
"5": "<p>'Fear him who, after he has killed, has authority to cast into Gehenna' — Gehenna (geennan) is the Greek form of the Hebrew gē'-hinnom (Valley of Hinnom), the ravine south of Jerusalem associated with the fires of Moloch worship (2 Kgs 23:10; Jer 7:31-32) and later Jewish apocalyptic's image of divine judgment (1 Enoch 27:1-3; 90:26-27; 4 Ezra 7:36; m. Avot 5.19). The saying establishes a hierarchy of fear: human coercive power (death) is less than divine eschatological authority (Gehenna). This reframes social persecution within a properly calibrated cosmology.</p>",
"6": "<p>Two sparrows sold for an assarion (the smallest Roman coin, worth 1/16 of a denarius) grounds the fearlessness argument in divine providence over the insignificant. The sparrow metaphor draws on Jewish tradition about divine care for all creatures (Ps 84:3; 147:9; m. Sanhedrin 4.5, which famously uses God's care for every soul). Luke's version gives five sparrows for two assaria (cheaper per sparrow) — emphasizing that even the mathematically 'cheapest' creature is known to God.</p>",
"7": "<p>'The hairs of your head are all numbered' — the idiom of divine enumeration of details impossible for humans to count appears in Jewish tradition (1 Sam 14:45; 2 Sam 14:11; 1 Kgs 1:52 where 'not a hair shall fall') and reflects the idea of God's absolute knowledge of every particular. In honor-shame culture, the patron's knowledge of the client's need was a mark of intimate care; Jesus frames divine providence in these relational-patronage terms. The disciples' worth exceeds sparrows by the implicit argument: God cares for sparrows; you are worth far more.</p>",
"8": "<p>'Everyone who acknowledges me before men, the Son of Man will acknowledge before the angels of God' — the divine court (throne-room with angels) is a common Second Temple judicial setting (Dan 7:10; 1 Enoch 47:3; T. Levi 3:5-8; Rev 4-5). Acknowledging Jesus before the human tribunal (social pressure) corresponds to Jesus's acknowledgment before the divine tribunal (eschatological vindication). The double tribunal structure (human/divine) motivates courage in the face of social rejection by pointing to the superior and final tribunal.</p>",
"9": "<p>The denial-before-men / denial-before-God parallelism creates the negative counterpart to v.8. In Roman judicial contexts, denial (arneomai) under pressure was a specific forensic act — renouncing association with a person or party under interrogation. The early Christian tradition about denial and confession before Roman magistrates (Acts 4:13-20; 5:29) gives this saying an immediate practical reference for Luke's readers facing potential legal examination about their allegiance to Jesus.</p>",
"10": "<p>The saying about blasphemy against the Holy Spirit has been extensively debated. In its Lukan context (distinct from the Beelzebul controversy of Mark/Matthew), it concerns final, definitive rejection of the Spirit's testimony rather than a single act. Jewish background: blasphemy (giddûph in Hebrew, blasphēmia in Greek) against the divine name was a capital offense in Torah (Lev 24:16; m. Sanhedrin 7.5). The extension to the Spirit (pneuma hagion) applies this to the divine self-revelation through the prophetic Spirit — the most direct divine communication.</p>",
"11": "<p>The promise of Spirit-assistance in synagogue and magistrate hearings provides concrete application of the fearlessness exhortation (vv.4-7). Synagogue discipline (flogging, exclusion) was the primary Jewish community sanction; magistrates (archai) and authorities (exousiai) refer to Roman and Herodian administrative officials. Acts 4:8, 6:10, and 13:9 provide explicit fulfillments of this promise. The instruction not to 'meditate beforehand' (mē promeletān) uses a technical rhetorical term for prepared speech — the Spirit provides improvisational, unpremeditated testimony.</p>",
"12": "<p>'The Holy Spirit will teach you in that very hour what to say' — the prophetic Spirit's role in providing speech before hostile authorities echoes the prophetic tradition where the Spirit fills the prophet's mouth (Isa 51:16; Jer 1:9; Ezek 3:27; Exod 4:12-16 where God promises Moses the words to speak). The promise applies the classical prophetic-inspiration model to the disciples' situation as witnesses before tribunals — they inhabit the prophetic role in the new covenant era.</p>",
"13": "<p>The interruption by 'someone in the crowd' asking Jesus to adjudicate an inheritance dispute reflects the rabbinic role of settling legal disputes. Torah commanded inheritance division (Num 27:8-11; Deut 21:17 — firstborn receives double), but disputes frequently arose. Rabbis were expected to function as arbitrators. The request is not unreasonable in cultural terms — Jesus has been recognized as a teacher with authority. His refusal to adjudicate is itself a statement about the nature of his authority and mission.</p>",
"14": "<p>'Who made me a judge or an arbitrator over you?' (tis me katestēsen kritēn ē meristēn eph' hymas) — the language echoes Moses's question in Exod 2:14 (LXX) when accused of overstepping in arbitrating between two Hebrews. The echo is likely deliberate: Jesus declines the role that Moses was questioned about, distinguishing his mission from civil judicial arbitration. His role is proclamation and healing, not legal settlement — even when cultural expectations include that function.</p>",
"15": "<p>'Take care, and be on guard against all covetousness' — the warning against pleonexia (covetousness, desire for more than one's share) addresses a standard Hellenistic vice-list item. Pleonexia was condemned in both Jewish and Greco-Roman ethics as the root of social injustice (Philo, Spec. Leg. 1.2; Dio Chrysostom, Or. 17; Prov 28:25). Jesus's grounding phrase 'for life does not consist in the abundance of possessions' is a programmatic statement about the relationship between material wealth and true human flourishing — the same counter-intuitive claim made by Stoic philosophers.</p>",
"16": "<p>The 'rich man' in the parable has no name and no identified vice — he is simply prosperous. His internal deliberation ('What shall I do?') is a literary device for revealing character through self-address, common in both Jewish parables (Pirke de-Rabbi Eliezer) and Hellenistic fiction. In first-century Palestinian agriculture, a bumper harvest was an uncommon windfall — the man's 'problem' of abundance would read as an enviable situation to most hearers, making Jesus's reframe unexpected.</p>",
"17": "<p>The rich man's 'having no place to store my crops' addresses a genuine agricultural management problem. Storage in first-century Palestine relied on stone-cut granaries, clay jars, or purpose-built storage buildings (apothekai). The Mishnah discusses granary construction and management (m. Bava Batra 6.1-7). The rich man's proposed solution (tear down and build larger) is economically rational within his framework — making his subsequent designation as 'fool' the theologically subversive element.</p>",
"18": "<p>The decision to 'pull down my barns and build larger' (kathairō — tear down) reflects the scale of investment required for significant agricultural storage. The language of self-sufficiency ('I will store all my grain and my goods') represents the ancient ideal of autarkeia (self-sufficiency) that both Stoics and Jewish sages valued — but Jesus reframes it as self-deception about life's ultimate contingency. The parable's target is not wealth per se but the assumption that accumulated wealth creates security.</p>",
"19": "<p>The rich man's self-address ('Soul, you have ample goods laid up for many years; rest, eat, drink, be merry') parodies the Epicurean maximization-of-pleasure philosophy, echoing Epicurus's own language (cf. Isa 22:13; Qoh 8:15; Tob 7:10). In Jewish wisdom tradition, the person who addresses their own soul as their authority figure — rather than God — epitomizes the 'fool' (nābāl) who acts without reference to divine reality (Ps 14:1). The self-contained self-sufficiency is the fool's defining characteristic.</p>",
"20": "<p>'This night your soul is required of you' (tautē tē nykti tēn psychēn sou apaitousin apo sou) — the plural 'they will require' (apaitousin) is a divine passive or an angelological reference: God's agents (angels of death in Jewish tradition) will claim the soul. The concept of God or divine agents 'requiring' or 'demanding back' the soul at death appears in rabbinic tradition (b. Berakhot 61a on Deut 6:5) and reflects the idea that human life is a loan from God. The man's goods, accumulated with such care, will belong to others — the irony of the parable's denouement.</p>",
"21": "<p>'Not rich toward God' (mē eis theon ploutōn) — the contrasting category of 'riches toward God' draws on Jewish tradition about deeds of righteousness (tzedaqah) as the true treasure: the Mishnah teaches that charity given to the poor is deposited in the divine treasury (m. Avot 2.9; T. Levi 13:5-6; Tob 4:7-9). The parable ends with the theological framework: the proper use of surplus is not self-storage but God-directed generosity that constitutes genuine wealth.</p>",
"22": "<p>The address 'therefore I tell you to my disciples' transitions from the crowd parable to inner-circle instruction. The anxiety-prohibition 'do not be anxious about your life' (mē merimnate tē psychē hymas) uses merimnaō — the same verb that appears in the Sower parable's thorns (8:14 — cares/merimnas choke the word). The prohibition of food-anxiety and clothing-anxiety addresses the two most fundamental material concerns of subsistence-level hearers in first-century Galilee, where clothing was expensive and food security uncertain.</p>",
"23": "<p>'For life is more than food, and the body more than clothing' — the a fortiori argument (from the greater to the lesser) is a common Jewish and rabbinic logical move (qal wahomer). If God gave the greater gift (life, body), the lesser gifts (food, clothing) can be trusted to follow. The argument implicitly appeals to creation theology: the Creator who gave life can be trusted to sustain it. This is the context in which the nature-observation arguments (ravens, lilies) operate.</p>",
"24": "<p>Ravens (korakes) — symbolically impure birds in Jewish law (Lev 11:15; Deut 14:14) yet used as positive examples of divine provision — were used in the Elijah narrative (1 Kgs 17:4-6) where ravens fed Elijah in the wilderness. The observation that ravens 'neither sow nor reap, and have no storehouse or barn, yet God feeds them' draws on the wisdom tradition about God's care for all creatures (Ps 147:9; Job 38:41). The irony of using ritually impure birds as positive examples of divine provision would have been striking to Jewish hearers.</p>",
"25": "<p>'Which of you by being anxious can add a single hour to his span of life?' (pēchyn hena) — the Greek pēchys means cubit (a unit of length), and meta tēs hēlikias could mean 'lifespan' or 'stature.' Most commentators read it as 'a moment to your lifespan.' The rhetorical question exposes the ineffectiveness of anxiety: it produces no measurable extension of life even on the most basic calculation. The Stoics similarly argued that anxiety about things beyond one's control was irrational (Epictetus, Enchiridion 1-2).</p>",
"26": "<p>'If you cannot do as small a thing as that' — the self-referential acknowledgment that adding a moment to life is in fact impossible (a 'small thing' in terms of being trivially easy, yet one humans cannot do) uses rhetorical irony. If anxiety cannot accomplish the smallest goal of extending life by one hour, it is irrational to deploy it toward the larger goals of food and clothing. The argument from futility reinforces the anxiety-prohibition with a practical rather than purely theological ground.</p>",
"27": "<p>'Consider the lilies' (katanoeite ta krina) — the specific flower is debated (anemones, lilies, or wildflowers generally). The observation that they 'neither toil nor spin' addresses the two primary domains of ancient material production: agricultural labor (toil) and textile production (spinning). Solomon's clothing — the apex of Israelite royal wealth — is the comparison point. Solomon's wardrobe, known through 1 Kgs 10:4-5 and later elaboration, represented the pinnacle of human luxury. Yet a wildflower exceeds it in natural splendor.</p>",
"28": "<p>'The grass of the field, which today is alive and tomorrow is thrown into the oven' — the brevity of wildflower life (a single season) is a common biblical and Jewish metaphor for human transience (Ps 90:5-6; 103:15-16; Isa 40:6-8; 1 Pet 1:24). The oven (klibanon) was a clay bread-oven fueled by dried grass and wood — the rapid transformation from living beauty to fuel is the image. Despite this radical impermanence, God clothes the grass with splendor. The a fortiori conclusion ('how much more will he clothe you, O you of little faith') is the logical destination.</p>",
"29": "<p>'Do not seek what you are to eat and what you are to drink, and do not be worried' (mē meteōrizesthe) — meteōrizō in this context means 'to be in suspense' or 'anxious' — literally 'lifted up' into uncertain hovering (like something suspended in the air). The command joins with v.22's prohibition. The phrase 'the nations of the world seek after all these things' (ta ethnē tou kosmou) establishes a contrast: anxiety-driven material seeking is characteristic of pagan Gentile life, not of God's covenant people who know a providing Father.</p>",
"30": "<p>'Your Father knows that you need them' — the grounding of the anxiety-prohibition in divine knowledge (oiden ho patēr hymōn) is Lukan: God's knowledge of specific need (not general provision) is the basis for trust. Jewish prayer tradition assumed that God knew human needs before petition (Sirach 23:19; Matt 6:8 makes this explicit). The personal parental address ('your Father') contrasts with the pagan nations' relationship to gods who must be informed of or bargained with for human needs.</p>",
"31": "<p>'Seek his kingdom, and these things will be added to you' — the kingdom-seeking reorientation substitutes the proper object of seeking (kingdom) for the anxiety-objects (food, clothing). 'Will be added' (prostethēsetai) implies the material gifts as surplus benefits that accompany the primary pursuit. Jewish wisdom tradition similarly argued that seeking wisdom first brings life's other goods as accompaniments (Prov 3:16-18; Wis 7:11-12 — 'all good things came to me along with her [wisdom]'). The logic is about proper ordering of pursuit.</p>",
"32": "<p>'Fear not, little flock' (mē phobou, to mikron poimnion) — the sheep/shepherd metaphor for God's relationship with Israel is pervasive in the Hebrew Bible (Ps 23; 80:1; Isa 40:11; Ezek 34; Zech 13:7). 'Little flock' acknowledges the disciples' numerical smallness and social vulnerability — they are marginal against the crowds and authorities surrounding them. 'Your Father's good pleasure to give you the kingdom' grounds the fearlessness of v.4-7 and the trust of v.22-31 in a specific divine decision (eudokēsen) rather than general providence.</p>",
"33": "<p>'Sell your possessions and give to the poor' is Luke's most radical almsgiving instruction — unique to Luke at this point (Matthew 19:21 has it addressed to the rich young ruler only). The instruction 'provide yourselves with moneybags that do not grow old, with a treasure in the heavens that does not fail' draws on Jewish traditions about charitable giving as depositing treasure with God (Tob 4:7-11; Sir 29:10-12; m. Peah 1.1). The contrast between earthly wealth (subject to theft and moth) and heavenly treasure echoes Matt 6:19-21 but is placed here in Luke as an instruction to the disciples.</p>",
"34": "<p>'Where your treasure is, there will your heart be also' — the aphorism identifies the relationship between investment and attention (heart = center of will and attention in Hebrew psychology). Jewish wisdom tradition similarly linked the location of one's concern with the orientation of one's whole person (Prov 4:23; Sir 17:16). The saying functions as a diagnostic: where a person's resources are directed reveals the true orientation of the person. The preceding instruction to put treasure in heaven is therefore an instruction to orient the heart toward heaven.</p>",
"35": "<p>'Stay dressed for action and keep your lamps burning' — the two commands invoke two distinct readiness images. 'Dressed for action' (hai osphai hymōn periezōsmenai) literally means 'let your loins be girded' — the tucking of the long robe into the belt for unimpeded movement, the standard preparation for labor or travel (Exod 12:11 at the Passover; 1 Kgs 18:46; Jer 1:17; Eph 6:14). The burning lamp (lychnoi kaiomenoi) suggests night-watch readiness. Together the two images describe active, alert preparation for unexpected arrival.</p>",
"36": "<p>The parable of the watchful servants awaiting the master's return from a wedding feast uses the specific cultural context of wedding celebrations, which in first-century Palestine could extend through the night. The master's knock at the door (krouō) is the signal of arrival that servants must be ready to respond to immediately. The reciprocal service in v.37 (the master will gird himself and serve the servants who were watching) is a shocking reversal of normal patron-client relations — masters did not serve servants. This reversal signals the parable's eschatological surprise.</p>",
"37": "<p>'Blessed are those servants whom the master finds awake when he comes' — makarism (beatitude) language applied to watchfulness parallels other Lukan beatitudes. The master's reciprocal service (he 'will gird himself and have them recline at table, and he will come and serve them') inverts the hierarchical domestic structure. In the broader Lukan narrative, this anticipates the Last Supper's 'I am among you as the one who serves' (22:27) — the parable projects Jesus's own pattern of servant-lordship onto the eschatological return.</p>",
"38": "<p>'Whether he comes in the second or third watch' — the watches of the night were counted differently in Jewish and Roman systems. Jewish division: three watches (Judg 7:19; Lam 2:19; Ps 90:4); Roman division: four watches (Matt 14:25). Luke's 'second or third watch' uses the Jewish system: second watch = midnight to 2am; third watch = 2am to dawn. The unpredictability of arrival in the late watches (when fatigue is greatest) intensifies the watchfulness demand — readiness when alertness is most difficult.</p>",
"39": "<p>The householder-and-thief analogy ('if the owner of the house had known at what hour the thief was coming, he would not have left his house to be broken into') uses a common wisdom comparison between unexpected arrival and unprepared households. The analogy is consistent across Q material (Matt 24:43-44) and appears in early Christian epistolary tradition (1 Thess 5:2; 2 Pet 3:10; Rev 3:3; 16:15). The thief image for the unexpected hour of divine visitation draws on prophetic tradition about the suddenness of divine judgment (Amos 4:12; Isa 26:20).</p>",
"40": "<p>'You also must be ready, for the Son of Man is coming at an hour you do not expect' — the Son of Man coming in unexpected judgment is the apocalyptic tradition of Daniel 7:13 applied to the disciples' eschatological situation. The present and future reference of 'Son of Man' in Luke is complex: sometimes clearly future-eschatological (17:24; 21:27), sometimes present (5:24; 9:22). Here the future-eschatological reference grounds the present readiness-command. The disciples' watchfulness is shaped by the Son of Man's coming, not by the master's arbitrary return time.</p>",
"41": "<p>Peter's question ('Lord, are you telling this parable for us or for everyone?') introduces a characteristically Lukan interrogative that allows Jesus to elaborate. The question reflects a genuine ambiguity in the parable: is watchful readiness a demand for the disciples specifically (as leaders entrusted with the community) or for all hearers? Jesus's response (the faithful steward parable, vv.42-48) expands the application to include leaders' accountability, implying that the disciples have a heightened responsibility corresponding to their position.</p>",
"42": "<p>The faithful and wise steward (oikonomos) was a specific social role in Greco-Roman domestic economy — a trusted slave or freedman who managed the household in the master's absence, responsible for food distribution, scheduling, and financial management. The position required both competence (phronimos, wise/prudent) and faithfulness (pistos) — the two qualities Jesus identifies. The steward's accountability to the master upon return was a recognized feature of ancient household management, documented in papyri regarding estate management throughout the Hellenistic period.</p>",
"43": "<p>'Blessed is that servant whom his master finds so doing when he comes' — the beatitude language applied to the diligent steward parallels v.37's beatitude for watchful servants. The specific 'doing' is food distribution at the proper time (eis ton kairon) — a temporal responsibility. The kairos (appointed time) of distribution reflects the household's ordered schedule. Faithfulness in time-specific responsibilities is the criterion of the beatitude — not merely intention but actual, ongoing performance of duties.</p>",
"44": "<p>'He will set him over all his possessions' — the promotion from household manager (specific domain) to total estate manager reflects the patronage reward system of Greco-Roman antiquity: faithful service in limited responsibility merited expanded authority. The parable here echoes the parable of the talents/minas where faithful stewardship over less leads to authority over more (Luke 19:17-19). The eschatological reward is framed in patron-client terms: expanded domain of responsibility and trust.</p>",
"45": "<p>The abusive servant who 'begins to beat the male and female servants, and to eat and drink and get drunk' represents the corruption of power when accountability is removed by expected delay. The servant calculates that 'my master is delayed in coming' (chronizei ho kyrios mou erchesthai) — the deliberate use of chronizō (to delay) is significant: the sense that the master's return is indefinitely postponed enables moral collapse. The three vices (beating, eating to excess, drunkenness) are classic Hellenistic vice-list entries marking social disorder.</p>",
"46": "<p>'The master of that servant will come on a day when he does not expect him and at an hour he does not know' — the unexpected arrival reverses the servant's calculation about delay. 'Will cut him in pieces' (dichotomēsei) is a harsh expression possibly meaning execution or severe punishment; the same verb appears in Matt 24:51. The alternative interpretation — that dichotomeō means 'assign a portion' (cutting him off from his share) — would give 'assign him a place with the unfaithful' as the full punishment. Either reading involves severe eschatological consequence for unfaithful leadership.</p>",
"47": "<p>'That servant who knew his master's will but did not get ready or act according to his will, will receive a severe beating' — the graduated punishment scheme (vv.47-48) reflects Jewish legal principles about graduated culpability based on knowledge: the one who sins with knowledge bears greater guilt than the one who sins in ignorance (Num 15:29-31; m. Makkot 1.7; b. Sanhedrin 72a distinguishing between shogeg and meizid — inadvertent and deliberate transgression). Jesus applies a universal moral principle to eschatological accountability.</p>",
"48": "<p>'Everyone to whom much was given, of him much will be required; and from him to whom they entrusted much, they will demand more' — this principle of proportional responsibility appears in Jewish wisdom (Wis 6:6; Sir 7:8), Roman law (Digest 50.17.23 on proportional liability), and Greek philosophy (Pericles's Funeral Oration on proportional obligation). Its universal formulation ('everyone') extends beyond the disciples to a general moral principle. For Luke's readers, this applies to economic wealth, community leadership, and apostolic authority alike.</p>",
"49": "<p>'I came to cast fire on the earth' — the fire-saying (unique to Luke in this form) draws on OT prophetic language about divine judgment as fire (Isa 66:15-16; Jer 4:4; Ezek 20:47-48; Mal 3:2; 4:1) and the Spirit/fire baptism announced by John (Luke 3:16). The saying has been interpreted as purifying fire (testing and refining), judgment fire (separating and destroying), or Pentecostal Spirit-fire (Acts 2:3). The second saying ('and how I wish it were already kindled') expresses Jesus's urgency for the eschatological process to be set in motion.</p>",
"50": "<p>'I have a baptism to be baptized with, and how great is my distress until it is accomplished!' — the baptism metaphor for overwhelming suffering/death appears in Jewish tradition (Ps 42:7; 69:1-2, 15 — flood waters overwhelming) and early Christian tradition (Mark 10:38-39 — can you drink my cup and be baptized with my baptism?). The 'distress' (synechomai — pressed together, constrained) describes psychological-emotional urgency rather than mere anxiety. Jesus's anticipation of his passion is portrayed as an active longing for the completion of the mission despite its cost.</p>",
"51": "<p>'Do you think that I have come to give peace on earth? No, I tell you, but rather division' — the saying (parallel in Matt 10:34-36, which has 'sword' not 'division/diamerismon') challenges messianic expectations. Peace (eirēnē) was the primary Jewish messianic expectation: Isa 9:6 (Prince of Peace), Zech 9:9-10 (king bringing peace), Psalms of Solomon 17 (messiah establishing peaceful rule). Jesus's negative answer (not peace but division) describes the actual social effect of his mission — not denying the ultimate eschatological peace, but naming the interim conflict his presence causes.</p>",
"52": "<p>The household division pattern (three against two, two against three) reflects the typical Palestinian household structure of extended family: father, mother, children, children's spouses (both son's wife and daughter-in-law). The specific listing anticipates the quotation of Micah 7:6 in v.53. In the honor-shame culture of the ancient Mediterranean, family loyalty was the most fundamental social bond — division within the household represented maximum social disruption, the collapse of the primary unit of social organization.</p>",
"53": "<p>The Micah 7:6 quotation ('For the son treats the father with contempt, the daughter rises up against her mother, the daughter-in-law against her mother-in-law; a man's enemies are the men of his own house') was used in Jewish apocalyptic tradition as a sign of the end times — the breakdown of familial order signaling eschatological upheaval (m. Sotah 9.15 uses it as an end-of-days sign; b. Sanhedrin 97a similarly). Jesus applies this established eschatological marker to the social effect of his mission, positioning the family conflicts his following causes within the larger apocalyptic horizon.</p>",
"54": "<p>'When you see a cloud rising in the west, you say immediately there will be a shower' — the meteorological observation reflects the specific Palestinian experience where westerly winds from the Mediterranean bring rain (cf. 1 Kgs 18:44-45 where Elijah's servant sees a small cloud from the sea before rain comes). The observation 'and so it happens' acknowledges empirically accurate weather prediction from cloud-signs. The immediate parallel with the southern wind (sirocco from the Negev bringing heat) establishes that the crowd has reliable interpretive skill for natural phenomena.</p>",
"55": "<p>The south wind (noton) in Palestine was the sirocco — the hot, dry desert wind from the Negev/Arabian Peninsula that brought extreme heat when it blew from the south. The crowd's confident prediction of heat from this wind sign was as meteorologically reliable as the rain-prediction from western clouds. The twofold weather-reading competence establishes the basis for the comparison: if you can read weather signs reliably, why can you not read eschatological signs equally well?</p>",
"56": "<p>'Hypocrites! You know how to interpret the appearance of earth and sky, but why do you not know how to interpret the present time?' — the accusation of hypocrisy targets the gap between natural-sign competence and eschatological-sign blindness. The 'present time' (ton kairon touton) uses kairos — the specific appointed, meaningful time — rather than chronos (mere chronological time). The crowd's failure to recognize the eschatological significance of the present moment (Jesus's ministry) despite signs available constitutes the hypocrisy: they apply interpretive skill selectively.</p>",
"57": "<p>'And why do you not judge for yourselves what is right?' — the question challenges autonomous moral judgment. In Jewish legal tradition, personal discernment (biqqoret, examination) was a recognized category — one was expected to examine one's own situation and draw appropriate conclusions. The Pharisaic approach was that communal/rabbinical interpretation governed; Jesus challenges hearers to apply direct judgment to their own eschatological situation rather than deferring to established religious interpretation that misses the present moment's significance.</p>",
"58": "<p>The adversary-on-the-way parable (parallel Matt 5:25-26) uses the context of Roman legal procedure: 'as you go with your accuser before the magistrate' (archōn) describes the walk to the Roman administrative court. Settlement before reaching the magistrate was a recognized legal strategy — courts favored pre-court resolution where possible. The 'officer' (praktōr) is the court enforcement officer who executes the magistrate's judgment. The 'last lepton' is the smallest coin in circulation (two leptons = one quadrans, the smallest Roman coin). The parable creates urgency for resolution before the final judgment.</p>",
"59": "<p>'You will never get out until you have paid the very last lepton' — the absolute finality of the debt-prison sentence underlines the parable's urgency. Debt imprisonment in the ancient world was a real institution: debtors were held until their families paid the debt on their behalf or they worked it off. The 'last lepton' as final payment threshold means the imprisonment continues until complete satisfaction — no partial release, no early exit. Applied to eschatological judgment, the parable warns that the final tribunal admits no negotiation or partial settlement.</p>"
},
"13": {
"1": "<p>The report about 'the Galileans whose blood Pilate had mingled with their sacrifices' is not attested in Josephus but is plausible given Pilate's well-documented brutality (Josephus, War 2.169-177; Ant. 18.55-62). Pilate's massacre of Samaritans (Josephus, Ant. 18.85-87) and his general contempt for Jewish religious sensitivities establish the pattern. The specific atrocity of killing Galileans in the temple court while they were offering sacrifices — mixing their blood with the sacrificial blood — would constitute both political assassination and ritual desecration.</p>",
"2": "<p>'Do you think that these Galileans were worse sinners than all the other Galileans because they suffered in this way?' — the retributive theodicy being challenged was a mainstream Jewish view (Deuteronomic covenant theology: suffering = punishment for sin). Deut 28-30 establishes national suffering as covenant consequence of disobedience; Job's friends argue a similar retributive logic at the individual level. Jesus explicitly rejects the automatic equation of catastrophe with exceptional personal guilt — the same move made in John 9:2-3 (who sinned, this man or his parents?).</p>",
"3": "<p>'No, I tell you; but unless you repent, you will all likewise perish' — the redirection from 'they were worse sinners' to 'you unless you repent' is the characteristic Lukan turn: catastrophe is a summons to personal repentance, not evidence about others' guilt. The word 'likewise' (hōsautōs) is pointed: the hearers themselves face a similar or equivalent catastrophe if they do not repent — not the same death by Roman violence but an analogous eschatological catastrophe. This verse has been understood as a veiled reference to the 70 CE Roman destruction of Jerusalem.</p>",
"4": "<p>The tower of Siloam (pyrgos tou Silōam) — a specific Jerusalem structure associated with the Pool of Siloam (Neh 3:15; John 9:7) in the southern part of the city — was apparently well known enough to require no further explanation. Josephus records extensive construction in first-century Jerusalem. The collapse killing eighteen people is not independently attested but is entirely plausible given ancient construction methods and the extensive building projects under Herod and his successors. The pairing of two recent Jerusalem disasters (political and accidental) provides two examples against the retributive interpretation.</p>",
"5": "<p>'Unless you repent, you will all likewise perish' — the repetition of v.3's refrain creates an emphatic inclusio around the two disaster-examples. The structural parallelism reinforces that both examples (Roman massacre, building collapse) serve the same theological point: sudden death is not a moral indicator about the deceased but a moral summons to the living. The Jerusalem focus of both examples (temple court, Jerusalem tower) may anticipate the subsequent journey narrative toward Jerusalem where Jesus himself will 'perish' at Roman hands.</p>",
"6": "<p>The parable of the barren fig tree was spoken in a vineyard context — a combination of fig tree planted in a vineyard (not unusual in ancient mixed-planting practices; Micah 4:4 and 1 Kgs 4:25 present vineyard-and-fig-tree as an ideal of peaceful prosperity). The owner comes seeking fruit for three years — the same three-year waiting period specified in Lev 19:23-25 (the first three years' fruit was forbidden, the fourth year's was holy, the fifth year's was for eating). The timeframe creates a legally informed expectation of fruit that has not materialized.</p>",
"7": "<p>'Cut it down. Why should it use up the ground?' — the owner's instruction frames the barren tree as an economic-agricultural problem: it occupies productive soil without return. In Palestinian mixed farming where vineyard space was valuable, a non-producing fig tree was waste of resources. The vineyard-keeper's intercession ('let it alone this one more year') introduces the motif of extended patience — additional time for response before judgment. Jewish tradition identified the fig tree with Israel (Hos 9:10; Jer 8:13; Mic 7:1; Nah 3:12) making the parable transparently allegorical.</p>",
"8": "<p>The vineyard keeper's proposed treatment ('I will dig around it and put on manure') describes intensive horticultural intervention: digging around the roots loosens compacted soil and improves drainage; manure fertilizes. These were standard ancient agricultural techniques for reviving stressed trees (cf. Columella, Res Rustica 5.9; Theophrastus, Historia Plantarum 2.7.3). The intensified care before cutting represents the extra effort of grace before judgment — the owner allows both additional time and additional remediation.</p>",
"9": "<p>'Then if it should bear fruit next year, well and good; but if not, you can cut it down' — the conditional resolution leaves the parable open-ended: Luke does not report the tree's ultimate fate. The narrative suspension invites hearers to see themselves within the story's open future — the 'one more year' of additional patience is the present moment of opportunity. In the context of the Jerusalem journey (chs 9:51-19:44), the parable serves as a final call to Israel's repentance before the catastrophe Jesus has just predicted (vv.3, 5).</p>",
"10": "<p>Jesus teaching in a synagogue on the Sabbath introduces the scene's conflict structure: Sabbath + synagogue + cure = expected Pharisaic confrontation. The synagogue (synagōgē) as the local institution of Jewish community life was where Torah was read, taught, and legal disputes adjudicated. Jesus's continued use of synagogues throughout his ministry (4:16-30; 4:44; 6:6; 8:41; 13:10; 13:14; 13:15; 21:12) establishes the synagogue as his primary teaching venue — he operates as a recognized teacher within institutional Judaism, not outside it.</p>",
"11": "<p>The woman 'who had had a disabling spirit for eighteen years' (pneuma asthenias — spirit of weakness/infirmity) is diagnosed in the narrative as a demonically-caused physical condition, then healed as a therapeutic act. The eighteen-year duration corresponds to the eighteen killed by the Siloam tower (v.4) — a numerical echo that may be deliberate. She was 'bent over and could not fully straighten herself' — the condition described (possibly spondylitis ankylosans or severe kyphosis) was both medically debilitating and socially marginalizing in a culture where physical posture conveyed honor status.</p>",
"12": "<p>'Woman, you are freed from your disability' — Jesus's declaration precedes the physical healing act (v.13). The declaration formula (apelysal apo tēs asthenias sou) uses apolyō — 'released, set free' — the vocabulary of liberation used in the Jubilee proclamation of Isa 61:1 and Luke 4:18 ('to set at liberty those who are oppressed'). The Sabbath healing thus performs the Jubilee-liberation that Jesus announced in Nazareth: the Sabbath (itself a Jubilee type) is the appropriate time for the liberation it symbolizes.</p>",
"13": "<p>'And immediately she was made straight, and she glorified God' — the immediacy (parachrēma) of the healing is a Lukan emphasis marking miraculous divine action (1:64; 4:39; 5:25; 8:44, 47, 55). 'Made straight' (anōrthōthē — from orthoomai) uses a straightening-verb with obvious metaphorical resonance: the crooked made straight, the humble exalted (Luke 1:52-53; Isa 40:4 — 'every crooked path shall be made straight'). Her immediate glorification of God is the proper response to divine encounter — she recognizes the source of her healing.</p>",
"14": "<p>The synagogue ruler's indignation ('There are six days in which work ought to be done') represents the Shammaite Pharisaic position on Sabbath healing: healing constituted melakhah (prohibited work) on the Sabbath except in life-threatening situations (m. Yoma 8.6; m. Shabbat 14.3-4 on permissible Sabbath medicine). The Shammaite school (dominant before 70 CE) prohibited most medical treatment on Sabbath; the Hillelite school was more permissive. The ruler's redirection to 'Come on those days and be healed' is a pastoral attempt to accommodate both healing and Sabbath observance without challenging Jesus directly.</p>",
"15": "<p>'You hypocrites! Does not each of you on the Sabbath untie his ox or his donkey from the manger and lead it away to water it?' — the animal-care argument draws on universal Jewish practice: Sabbath restrictions explicitly permitted animal care for the animals' welfare (CD XI.5-6 allows loosening animal stalls on Sabbath for watering; m. Shabbat 5.1-4 discusses what animals may carry on Sabbath). The qal wahomer (light to heavy) argument: if animal-loosing is permitted on Sabbath, how much more should a woman-loosing be permitted?</p>",
"16": "<p>'And ought not this woman, a daughter of Abraham whom Satan bound for eighteen years, be loosed from this bond on the Sabbath day?' — three elements load the argument: (1) 'daughter of Abraham' — she is a covenant member, more valuable than livestock; (2) 'whom Satan bound' — the demonically-caused nature of the illness means healing is liberation from the adversary, not mere medical treatment; (3) 'eighteen years' — the extended duration increases both the urgency and the moral claim for immediate release. The Sabbath is precisely the right day for liberation from Satan's bondage, not a day that must wait.</p>",
"17": "<p>'As he said these things, all his adversaries were put to shame, and all the people rejoiced at all the glorious things that were done by him' — the triple 'all' (pantes/pas) marks the total contrast between the shamefaced opponents and the rejoicing crowd. 'Put to shame' (katēschynonto) uses the honor-shame vocabulary of public humiliation — Jesus has won the social contest by successfully humiliating his critics in public discourse. The crowd's joy (echairen) and wonder at 'the glorious things' (tois endoxois) frames the Sabbath healing within the larger context of God's glory being revealed through Jesus's ministry.</p>",
"18": "<p>The mustard seed parable (parallel Matt 13:31-32; Mark 4:30-32) is placed immediately after the Sabbath-woman healing in Luke, suggesting thematic connection: the kingdom's small beginnings (a seed) and large results (a tree) mirror the healing of one overlooked woman and the far-reaching implications of kingdom liberation. The mustard plant (Brassica nigra or sinapis alba) was proverbially the smallest of seeds in Palestinian Jewish tradition (m. Niddah 5.2 uses it as a standard of small measurement) yet grew into a large shrub (not technically a tree in botanical classification).</p>",
"19": "<p>'It is like a grain of mustard seed that a man took and sowed in his garden, and it grew and became a tree, and the birds of the air made nests in its branches' — the birds nesting in the branches echoes Dan 4:12 (LXX), where Nebuchadnezzar's kingdom is symbolized by a great tree sheltering birds of every kind (also Ezek 17:23; 31:6). The Daniel echo (a Gentile empire's tree) is ironic: the kingdom of God, starting from a seed smaller than an empire, becomes the sheltering tree that the great empires merely imitated. The birds represent all nations finding refuge in the kingdom.</p>",
"20": "<p>The leaven parable (parallel Matt 13:33) is paired with the mustard seed parable — both use the 'hidden-to-manifest' pattern of kingdom growth. Luke's version is identical to Matthew's in content. The parable is unique in using leaven positively (normally associated with corruption in Jewish contexts: Exod 12:15; Lev 2:11; 1 Cor 5:6-8) — the deliberate subversion of a negative symbol into a positive kingdom image is the parable's rhetorical edge. The Pharisees' 'leaven' (12:1) is corrupt; the kingdom's 'leaven' is transformative.</p>",
"21": "<p>'Leaven that a woman took and hid in three measures of flour' — three measures (sata tria, Hebrew se'im) is approximately 22 liters — the amount Sarah used to make bread for the three divine visitors in Gen 18:6 (the LXX uses the same saton measure). The echo to the Abrahamic hospitality narrative may be deliberate, linking the kingdom's quiet permeation with the divine visitation to Abraham. The 'hiding' (enkrypto — to conceal within) of the leaven describes how the kingdom's presence permeates invisibly until the whole is leavened — process hidden until outcome manifest.</p>",
"22": "<p>The travel notice ('he went on his way through towns and villages, teaching and journeying toward Jerusalem') marks the ongoing Lukan travel narrative (9:51-19:44). Luke's unique extended journey section structures the middle third of the Gospel as a movement toward Jerusalem where the passion will occur. The teaching-while-traveling pattern reflects the itinerant rabbi model. The Jerusalem destination is the theological horizon that gives the journey its weight — everything taught along the way is shaped by the approaching confrontation in the capital.</p>",
"23": "<p>The question 'Lord, will those who are saved be few?' reflects a live debate in Second Temple Judaism about the scope of salvation. The Shammaite school held that few would be saved; the Hillelite school was more generous. 4 Ezra 7:47-48 expresses anguish about the few who will be saved ('for the world was made for our sakes; but I do not understand why our world must be destroyed'). The question expects a quantitative answer about size of the saved group; Jesus redirects to a qualitative imperative about personal striving for the narrow door.</p>",
"24": "<p>'Strive to enter through the narrow door. For many, I tell you, will seek to enter and will not be able' — agōnizesthe (strive) uses the athletic competition word (agōn = contest, competition) — the same root as English 'agonize.' The narrow door (thyra tēs stenas) draws on prophetic tradition about a narrow way (Isa 26:2; Ps 118:20 — 'the gate of the LORD through which the righteous enter'). The warning that many will seek to enter but not be able warns against assuming that desire for salvation automatically achieves it — actual striving (not passive expectation) is required.</p>",
"25": "<p>'When once the master of the house has risen and shut the door' — the closing of the door is the definitive moment of eschatological exclusion. The locked-door image appears in Jewish apocalyptic tradition (4 Ezra 7:3-14 — a narrow city gate; 2 Enoch 42:5 — heaven's gate closed). Those who then stand outside knocking and saying 'Lord, open to us' (Kyrie, anoixon hēmin) will receive the response 'I do not know where you come from' — the denial of relational recognition. In ancient Mediterranean culture, the patron's knowledge of the client was the basis of access; unknown = excluded.</p>",
"26": "<p>'We ate and drank in your presence, and you taught in our streets' — the excluded group's claim of past social proximity to Jesus is the basis of their appeal. Eating and drinking together in ancient Mediterranean culture was a bond of social-covenantal significance — sharing a table created lasting relational claims. Teaching in the streets was a public event with witnesses. The excluded group's claim is not fabricated: Jesus did in fact eat, drink, and teach publicly in towns throughout Galilee and Judea. The surprise is that social proximity proves insufficient for eschatological recognition.</p>",
"27": "<p>'But he will say, I tell you, I do not know where you come from. Depart from me, all you workers of iniquity' (Ps 6:8 LXX) — the Psalm 6:8 citation uses the Septuagint form (apochōreite ap' emou, pantes hoi ergazomenoi tēn anomian). The Psalm is a lament of the righteous sufferer calling on enemies to depart; Jesus places it on the lips of the eschatological judge rejecting those who appealed to social proximity. The 'workers of iniquity' label reverses their self-presentation as Jesus's associates — whatever their public proximity, their actual practice was lawlessness.</p>",
"28": "<p>'In that place there will be weeping and gnashing of teeth, when you see Abraham and Isaac and Jacob and all the prophets in the kingdom of God but you yourselves cast out' — the three patriarchs and the prophets represent the full scope of Israel's covenant history. 'Weeping and gnashing of teeth' (klauthmous kai brygmon tōn odontōn) appears seven times in Matthew and here alone in Luke — a Matthean phrase in the parallel tradition describing eschatological exclusion. The visual anguish of seeing others admitted while being 'cast out' (ekballomenous) intensifies the exclusion's shame dimension in honor-shame terms.</p>",
"29": "<p>'And people will come from east and west, and from north and south, and recline at table in the kingdom of God' — the gathering of Gentiles from the four directions echoes multiple OT texts: Isa 43:5-6 ('I will bring your offspring from the east, and from the west I will gather you'); Ps 107:3; Zech 8:7-8. The table-reclining (anaklithēsontai) uses the posture of the honored guest at the banquet — the Gentile nations will recline as honored guests at the eschatological feast that Israel's covenant descendants miss by failing to enter the narrow door.</p>",
"30": "<p>'And behold, some are last who will be first, and some are first who will be last' — the reversal saying appears in various Synoptic contexts (Matt 19:30; 20:16; Mark 10:31). Here it summarizes the preceding reversal: those expecting first-place (Israel by covenant heritage) find themselves last or excluded; those expecting to be last (Gentiles by ethnic position) find themselves first. The reversal logic is consistent throughout Luke: the Magnificat's 'the mighty brought low, the humble exalted' (1:52); the Beatitudes' 'blessed are the poor'; the Rich Man and Lazarus's reversal in the afterlife.</p>",
"31": "<p>'Some Pharisees came and said to him, Get away from here, for Herod wants to kill you' — the specific identification of Herod Antipas as the threat and the Pharisees as warners creates an unexpected dynamic: Pharisees (normally Jesus's opponents in Luke) here appear as protective informants. Whether this is genuine concern, an attempt to redirect Jesus away from their territory, or a test of his reaction is deliberately ambiguous. Herod Antipas's execution of John the Baptist (3:19-20; 9:9) gives the death-threat credibility.</p>",
"32": "<p>'Go and tell that fox' — calling Herod Antipas a 'fox' (alōpēki) is a striking political insult. In Greek tradition, the fox symbolized craftiness and low cunning (Aesop's fables; Thucydides 1.138 of Themistocles). In Semitic usage, the fox was associated with insignificance and minor destructiveness (Song 2:15 — 'little foxes that spoil the vines'). The dismissal of a Herodian tetrarch as a mere fox — while Jesus contrasts himself with a greater purpose — is a display of honor-claiming courage that would resonate with Mediterranean hearers attuned to status rhetoric.</p>",
"33": "<p>'Nevertheless, I must go on my way today and tomorrow and the day following, for it cannot be that a prophet should perish away from Jerusalem' — 'it cannot be' (ouk endechetai) expresses divine necessity (dei in other formulations). The ironic logic: Jerusalem the prophet-killing city is the only proper place for Jesus's death. Prophets were expected to die in Jerusalem — the tradition of Jerusalem killing prophets was established (1 Kgs 19:10, 14; 2 Chr 24:20-21; Jer 26:23; Neh 9:26). Jesus's journey toward Jerusalem is thus shaped by prophetic typology: he goes to die where prophets die.</p>",
"34": "<p>'O Jerusalem, Jerusalem, the city that kills the prophets and stones those who are sent to it!' — the lament over Jerusalem parallels Matt 23:37-39 (placed there in a later context). The double address ('Jerusalem, Jerusalem') is a Hebrew lament form appearing in biblical poetry (2 Sam 18:33 'O my son Absalom'; Gen 22:11 'Abraham, Abraham'; Exod 3:4 'Moses, Moses'). The city as the subject — not merely its inhabitants — anthropomorphizes Jerusalem as a character with a consistent historical identity: the prophet-killer across generations.</p>",
"35": "<p>'Behold, your house is forsaken' — the 'house' (oikos) likely refers to the temple (as in Jer 12:7 'I have forsaken my house, abandoned my heritage'; cf. 1 Kgs 9:7-8). The tradition of divine abandonment of the temple before its destruction had precedent in Ezekiel's vision of the divine glory departing the temple (Ezek 10:18-19; 11:22-23) before the Babylonian destruction. The following 'You will not see me until you say, Blessed is he who comes in the name of the Lord' (Ps 118:26) introduces a conditional: potential restoration tied to recognition of Jesus as the Blessed One at his entry into Jerusalem (Luke 19:38).</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'luke')
    merge_comm(existing, LUKE_CH12_13)
    save_comm('mkt-context', 'luke', existing)
    ch12 = len(existing.get('12', {}))
    ch13 = len(existing.get('13', {}))
    print(f'Luke 12: {ch12}/59 verses. Luke 13: {ch13}/35 verses.')

if __name__ == '__main__':
    main()
